class Solution:
    def minMoves(self, balance):
        n = len(balance)
        total = sum(balance)
        if total < 0:
            return -1
        neg_idx = None
        for i, b in enumerate(balance):
            if b < 0:
                neg_idx = i
                break
        if neg_idx is None:
            return 0
        deficit = -balance[neg_idx]
        items = []
        for i in range(n):
            if i == neg_idx:
                continue
            best = None
            for direction in (1, -1):
                d = 0
                cur = i
                while cur != neg_idx:
                    cur = (cur + direction) % n
                    d += 1
                if best is None or d < best:
                    best = d
            items.append((best, balance[i]))
        items.sort(key=lambda p: p[0])
        moves = 0
        remaining = deficit
        for cost, amt in items:
            if remaining <= 0:
                break
            take = amt if amt < remaining else remaining
            moves += take * cost
            remaining -= take
        return moves

