var minMoves = function(balance) {
    const n = balance.length;
    let total = 0;
    for (const b of balance) total += b;
    if (total < 0) return -1;
    let negIdx = -1;
    for (let i = 0; i < n; i++) {
        if (balance[i] < 0) { negIdx = i; break; }
    }
    if (negIdx === -1) return 0;
    let deficit = -balance[negIdx];
    const items = [];
    for (let i = 0; i < n; i++) {
        if (i === negIdx) continue;
        const cw = ((negIdx - i) % n + n) % n;
        const ccw = n - cw;
        const cost = Math.min(cw, ccw);
        items.push([cost, balance[i]]);
    }
    items.sort((a, b) => a[0] - b[0]);
    let moves = 0;
    let remaining = deficit;
    for (const [cost, amt] of items) {
        if (remaining <= 0) break;
        const take = Math.min(amt, remaining);
        moves += take * cost;
        remaining -= take;
    }
    return moves;
};
